// In-game infinite-tier scaling (combatStore / tierMonsterMultiplier):
// hpMult = 1 + (tier-1)*0.5,  damageMult = 1 + (tier-1)*0.35
const hpMult  = 1 + (tier - 1) * 0.5
const dmgMult = 1 + (tier - 1) * 0.35

// Decoupled Normal/Nightmare/Hell scaling — used in fullRunSim + future in-game implementation.
// Tuned via 800-player diffTransitionSim: all 3 classes BALANCED.
export function applyTierScaling(monster: MonsterInstance, diffTier: number): MonsterInstance {
  if (diffTier <= 1) return monster   // Normal: no scaling
  let hpMult: number, dmgMult: number
  if (diffTier === 2) {
    hpMult  = 2.5   // Nightmare: ~2.5× as tanky as Normal
    dmgMult = 1.80  // +80% dmg — manageable with Normal-cleared gear
  } else {
    hpMult  = 3.1   // Hell: very tanky — DPS constraint
    dmgMult = 2.0   // +100% dmg — lower than HP so spike deaths are reduced
  }
  const scaledHp = Math.round(monster.maxHp * hpMult)
  return { ...monster, maxHp: scaledHp, currentHp: scaledHp, damage: [
    Math.round(monster.damage[0] * dmgMult),
    Math.round(monster.damage[1] * dmgMult),
  ]}
}
// Balance targets (diffTransitionSim, 800 players per class):
//   NM A1: 10-35% survival  → actual: warrior 31%, rogue 19%, sorc 22%  ✓
//   NM A5: 50-80% survival  → actual: warrior 78%, rogue 75%, sorc 64%  ✓
//   Hell A1: 5-25% survival → actual: warrior 25%, rogue  9%, sorc 13%  ✓
//   Hell A5: 30-60% survival → actual: warrior 50%, rogue 28%, sorc 24% ✓

if (s.floor >= 10) {
  const completedTier = s.tier
  const isFirstClear  = !s.careerStats.tiersCleared.includes(completedTier)
  const tiersCleared  = isFirstClear
    ? [...s.careerStats.tiersCleared, completedTier]
    : s.careerStats.tiersCleared
  set({
    tier: s.tier + 1,
    floor: 1,
    firstTimeTierClear: isFirstClear ? completedTier : null,
    careerStats: { ...s.careerStats, tiersCleared },
  })
}

ascendRun: (seed?) => {
  const s = get()
  const lastEntry = s.graveyard.length > 0 ? s.graveyard[s.graveyard.length - 1] : null
  set({
    floor: 1,
    seed: seed ?? Date.now(),
    screen: 'grid',
    runStarted: true,
    ghostCharm: lastEntry?.item ?? null,
    careerStats: { ...s.careerStats, ascensions: s.careerStats.ascensions + 1 },
  })
  scheduleSave()
}

{won && graveyard.length > 0 && (
  <TouchableOpacity
    style={endStyles.ascendBtn}
    onPress={() => { ascendRun(); setScreen('classSelect') }}
  >
    <Text style={endStyles.ascendBtnText}>⬆ ASCEND</Text>
    <Text style={endStyles.ascendBtnSub}>Start fresh · Ghost Echo pre-loaded</Text>
  </TouchableOpacity>
)}
